import React from "react";
import PasswordField from "./PasswordField";
import FormField from "./FormField";

const s = {
  checkboxRow: { display: "flex", alignItems: "flex-start", gap: "8px", marginBottom: "20px" },
  checkbox: { marginTop: "3px", accentColor: "var(--brand)", width: "16px", height: "16px", flexShrink: 0, cursor: "pointer" },
  checkboxLabel: { fontSize: "12px", color: "var(--text-muted)", lineHeight: 1.6, cursor: "pointer" },
  btnBack: {
    flex: "0 0 90px", padding: "13px", background: "#888",
    border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
    fontSize: "14px", fontWeight: 600, cursor: "pointer", minHeight: "48px",
  },
  btnContinue: {
    flex: 1, padding: "13px", background: "var(--accent)",
    border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
    fontSize: "15px", fontWeight: 700, cursor: "pointer",
    boxShadow: "var(--shadow-btn)", transition: "background .15s", minHeight: "48px",
  },
  divider: { display: "flex", alignItems: "center", gap: "10px", margin: "16px 0" },
  hr: { flex: 1, border: "none", borderTop: "1px solid var(--border)" },
  divText: { fontSize: "12px", color: "var(--text-muted)", whiteSpace: "nowrap" },
  btnGoogle: {
    width: "100%", padding: "11px", border: "1px solid var(--border)",
    borderRadius: "var(--radius-sm)", background: "#fff", fontSize: "14px",
    color: "#444", fontWeight: 500, cursor: "pointer", display: "flex",
    alignItems: "center", justifyContent: "center", gap: "10px",
    transition: "background .15s", minHeight: "48px",
  },
  googleG: { fontWeight: 700, fontSize: "16px", color: "#ea4335" },
  errMsg: { fontSize: "11px", color: "var(--error)", marginTop: "4px" },
};

export default function Step2Security({ fields, errors, updateField, onContinue, onBack, onGoogle, loading }) {
  return (
    <div className="fade-slide-in">
      <PasswordField id="password" label="Create Password"
        value={fields.password} onChange={(v) => updateField("password", v)}
        error={errors.password} showStrength />
      <PasswordField id="confirmPassword" label="Confirm Password"
        value={fields.confirmPassword} onChange={(v) => updateField("confirmPassword", v)}
        error={errors.confirmPassword} />
      <FormField label="Referral Code" name="referral" value={fields.referral}
        onChange={(v) => updateField("referral", v)} error={errors.referral}
        placeholder="e.g. SK2024DIWALI" optional />

      <div style={s.checkboxRow}>
        <input type="checkbox" id="terms" style={s.checkbox}
          checked={fields.termsAccepted}
          onChange={(e) => updateField("termsAccepted", e.target.checked)} />
        <label htmlFor="terms" style={s.checkboxLabel}>
          I agree to ShopKart's <a href="#terms">Terms of Service</a>,{" "}
          <a href="#privacy">Privacy Policy</a>, and consent to receiving marketing communications.
        </label>
      </div>
      {errors.termsAccepted && (
        <p style={{ ...s.errMsg, marginTop: "-14px", marginBottom: "14px" }}>{errors.termsAccepted}</p>
      )}

      {/* btn-row-2col stacks to column-reverse on mobile (continue on top) */}
      <div className="btn-row-2col">
        <button style={s.btnBack} onClick={onBack} disabled={loading}>← Back</button>
        <button style={s.btnContinue} onClick={onContinue} disabled={loading}
          onMouseEnter={(e) => { e.target.style.background = "var(--accent-dark)"; }}
          onMouseLeave={(e) => { e.target.style.background = "var(--accent)"; }}>
          {loading ? "Sending OTP…" : "Continue →"}
        </button>
      </div>

      <div style={s.divider}>
        <hr style={s.hr} />
        <span style={s.divText}>or register with</span>
        <hr style={s.hr} />
      </div>

      <button style={s.btnGoogle} onClick={onGoogle}
        onMouseEnter={(e) => { e.target.style.background = "#f5f5f5"; }}
        onMouseLeave={(e) => { e.target.style.background = "#fff"; }}>
        <span style={s.googleG}>G</span> Continue with Google
      </button>
    </div>
  );
}
